export const PERIOD_STATUS_OPTIONS = [
  { value: 'Open', label: 'Mở' },
  { value: 'Closed', label: 'Đã khóa mềm' },
  { value: 'Locked', label: 'Đã khóa cứng' },
];

export const MONTH_OPTIONS = Array.from({ length: 12 }, (_, i) => ({
  value: String(i + 1),
  label: `Tháng ${i + 1}`,
}));

/**
 * Generate year options for dropdown selects.
 * @param startYear Năm bắt đầu (từ env VITE_START_YEAR). Nếu không set, dùng span=5 năm quanh năm hiện tại.
 */
export const yearOptions = (startYear?: number) => {
  const currentYear = new Date().getFullYear();
  if (startYear != null) {
    const endYear = currentYear + 2;
    const years: { value: string; label: string }[] = [];
    for (let y = startYear; y <= endYear; y++) {
      years.push({ value: String(y), label: String(y) });
    }
    return years;
  }
  // fallback: 5 years centered around current year
  const span = 5;
  return Array.from({ length: span }, (_, i) => {
    const year = currentYear - 2 + i;
    return { value: String(year), label: String(year) };
  });
};
